#!/usr/bin/perl
use strict;
use warnings;
use File::Spec;
use Cwd 'abs_path';

my $plugin_dir = $ARGV[0] || 'plugins';
my %plugins;
my %plugin_hooks = (
    'init' => [],
    'pre_process' => [],
    'process' => [],
    'post_process' => [],
    'cleanup' => []
);

sub load_plugins {
    my ($dir) = @_;
    
    unless (-d $dir) {
        warn "Plugin directory '$dir' does not exist\n";
        return;
    }
    
    opendir(my $dh, $dir) or die "Cannot open directory '$dir': $!\n";
    my @plugin_files = grep { /\.pl$/ && -f "$dir/$_" } readdir($dh);
    closedir($dh);
    
    foreach my $plugin_file (@plugin_files) {
        my $plugin_path = File::Spec->catfile($dir, $plugin_file);
        load_plugin($plugin_path);
    }
}

sub load_plugin {
    my ($plugin_path) = @_;
    
    open(my $fh, '<', $plugin_path) or do {
        warn "Cannot open plugin file '$plugin_path': $!\n";
        return;
    };
    
    my $plugin_code = do { local $/; <$fh> };
    close($fh);
    
    my $plugin_name = $plugin_path;
    $plugin_name =~ s/.*[\/\\]//;
    $plugin_name =~ s/\.pl$//;
    
    print "Loading plugin: $plugin_name from $plugin_path\n";
    
    my %plugin_context = (
        name => $plugin_name,
        data => {},
        register_hook => sub {
            my ($hook_name, $callback) = @_;
            if (exists $plugin_hooks{$hook_name}) {
                push @{$plugin_hooks{$hook_name}}, {
                    name => $plugin_name,
                    callback => $callback
                };
                print "  Registered hook: $hook_name for plugin $plugin_name\n";
            } else {
                warn "  Unknown hook: $hook_name\n";
            }
        },
        log => sub {
            my ($message) = @_;
            print "[$plugin_name] $message\n";
        }
    );
    
    eval {
        my $result = eval $plugin_code;
        if ($@) {
            die "Plugin execution error: $@";
        }
        
        if (ref($result) eq 'CODE') {
            $result->(\%plugin_context);
        }
        
        $plugins{$plugin_name} = \%plugin_context;
        print "  Successfully loaded plugin: $plugin_name\n";
    };
    
    if ($@) {
        warn "Failed to load plugin '$plugin_name': $@\n";
    }
}

sub execute_hooks {
    my ($hook_name, $data) = @_;
    
    return unless exists $plugin_hooks{$hook_name};
    
    print "\nExecuting hooks for: $hook_name\n";
    
    foreach my $hook (@{$plugin_hooks{$hook_name}}) {
        eval {
            print "  Running hook from plugin: $hook->{name}\n";
            $hook->{callback}->($data);
        };
        if ($@) {
            warn "  Hook execution error in plugin '$hook->{name}': $@\n";
        }
    }
}

sub process_data {
    my ($input_data) = @_;
    
    my %data = (
        input => $input_data,
        output => '',
        metadata => {},
        processed => 0
    );
    
    execute_hooks('init', \%data);
    execute_hooks('pre_process', \%data);
    execute_hooks('process', \%data);
    execute_hooks('post_process', \%data);
    execute_hooks('cleanup', \%data);
    
    return \%data;
}

sub list_plugins {
    print "\nLoaded Plugins:\n";
    foreach my $name (sort keys %plugins) {
        print "  - $name\n";
    }
    
    print "\nRegistered Hooks:\n";
    foreach my $hook (sort keys %plugin_hooks) {
        my $count = scalar @{$plugin_hooks{$hook}};
        print "  $hook: $count hook(s)\n";
        foreach my $h (@{$plugin_hooks{$hook}}) {
            print "    - $h->{name}\n";
        }
    }
}

sub reload_plugins {
    print "\nReloading all plugins...\n";
    %plugins = ();
    %plugin_hooks = (
        'init' => [],
        'pre_process' => [],
        'process' => [],
        'post_process' => [],
        'cleanup' => []
    );
    load_plugins($plugin_dir);
}

sub execute_inline_code {
    my ($code) = @_;
    
    print "\nExecuting inline code...\n";
    
    my $result;
    eval {
        $result = eval $code;
        if ($@) {
            die "Inline code execution error: $@";
        }
    };
    
    if ($@) {
        warn "Failed to execute inline code: $@\n";
        return undef;
    }
    
    return $result;
}

print "=== Perl Plugin System ===\n";
print "Plugin Directory: $plugin_dir\n\n";

load_plugins($plugin_dir);
list_plugins();

print "\n=== Processing Test Data ===\n";
my $result = process_data("Sample input data for processing");

print "\n=== Processing Results ===\n";
print "Input: $result->{input}\n";
print "Output: $result->{output}\n";
print "Processed: $result->{processed}\n";
print "Metadata:\n";
foreach my $key (sort keys %{$result->{metadata}}) {
    print "  $key: $result->{metadata}->{$key}\n";
}

print "\n=== Interactive Mode ===\n";
print "Commands: list, reload, exec <code>, process <data>, quit\n";

while (1) {
    print "\n> ";
    my $input = <STDIN>;
    last unless defined $input;
    chomp $input;
    
    last if $input eq 'quit';
    
    if ($input eq 'list') {
        list_plugins();
    }
    elsif ($input eq 'reload') {
        reload_plugins();
    }
    elsif ($input =~ /^exec\s+(.+)$/) {
        my $code = $1;
        my $result = execute_inline_code($code);
        print "Result: " . (defined $result ? $result : 'undef') . "\n";
    }
    elsif ($input =~ /^process\s+(.+)$/) {
        my $data = $1;
        my $result = process_data($data);
        print "Output: $result->{output}\n";
    }
    else {
        print "Unknown command\n";
    }
}

